49: 	// Plugins should define their entry point in the standard `main` property of `package.json`
50: 	try {
51: 		libraryPath = pluginData.path;
52: 		Plugins.libraries[pluginData.id] = require(libraryPath);
53: 	} catch (e) {
54: 		// DEPRECATED: @1.15.0, remove in version >=1.17
55: 		// for backwards compatibility
56: 		// if that fails, fall back to `pluginData.library`
57: 		if (pluginData.library) {
58: 			winston.warn(`   [plugins/${pluginData.id}] The plugin.json field "library" is deprecated. Please use the package.json field "main" instead.`);
59: 			winston.verbose(`[plugins/${pluginData.id}] See https://github.com/NodeBB/NodeBB/issues/8686`);
60: 
61: 			libraryPath = path.join(pluginData.path, pluginData.library);
62: 			Plugins.libraries[pluginData.id] = require(libraryPath);
63: 		} else {
