192: Plugins.normalise = async function (apiReturn) {
193: 	const pluginMap = {};
194: 	const { dependencies } = require(paths.currentPackage);
195: 	apiReturn = Array.isArray(apiReturn) ? apiReturn : [];
196: 	apiReturn.forEach((packageData) => {
197: 		packageData.id = packageData.name;
198: 		packageData.installed = false;
199: 		packageData.active = false;
200: 		packageData.url = packageData.url || (packageData.repository ? packageData.repository.url : '');
201: 		pluginMap[packageData.name] = packageData;
202: 	});
203: 
204: 	let installedPlugins = await Plugins.showInstalled();
205: 	installedPlugins = installedPlugins.filter(plugin => plugin && !plugin.system);
206: 
207: 	installedPlugins.forEach((plugin) => {
208: 		// If it errored out because a package.json or plugin.json couldn't be read, no need to do this stuff
209: 		if (plugin.error) {
210: 			pluginMap[plugin.id] = pluginMap[plugin.id] || {};
211: 			pluginMap[plugin.id].installed = true;
212: 			pluginMap[plugin.id].error = true;
213: 			return;
214: 		}
215: 
216: 		pluginMap[plugin.id] = pluginMap[plugin.id] || {};
217: 		pluginMap[plugin.id].id = pluginMap[plugin.id].id || plugin.id;
218: 		pluginMap[plugin.id].name = plugin.name || pluginMap[plugin.id].name;
219: 		pluginMap[plugin.id].description = plugin.description;
220: 		pluginMap[plugin.id].url = pluginMap[plugin.id].url || plugin.url;
221: 		pluginMap[plugin.id].installed = true;
222: 		pluginMap[plugin.id].isTheme = themeNamePattern.test(plugin.id);
223: 		pluginMap[plugin.id].error = plugin.error || false;
224: 		pluginMap[plugin.id].active = plugin.active;
225: 		pluginMap[plugin.id].version = plugin.version;
226: 		pluginMap[plugin.id].settingsRoute = plugin.settingsRoute;
227: 		pluginMap[plugin.id].license = plugin.license;
228: 
229: 		// If package.json defines a version to use, stick to that
230: 		if (dependencies.hasOwnProperty(plugin.id) && semver.valid(dependencies[plugin.id])) {
231: 			pluginMap[plugin.id].latest = dependencies[plugin.id];
232: 		} else {
233: 			pluginMap[plugin.id].latest = pluginMap[plugin.id].latest || plugin.version;
234: 		}
235: 		pluginMap[plugin.id].outdated = semver.gt(pluginMap[plugin.id].latest, pluginMap[plugin.id].version);
236: 	});
237: 
238: 	if (nconf.get('plugins:active')) {
239: 		nconf.get('plugins:active').forEach((id) => {
240: 			pluginMap[id] = pluginMap[id] || {};
241: 			pluginMap[id].active = true;
242: 		});
243: 	}
244: 
245: 	const pluginArray = Object.values(pluginMap);
246: 
247: 	pluginArray.sort((a, b) => {
248: 		if (a.name > b.name) {
249: 			return 1;
250: 		} else if (a.name < b.name) {
251: 			return -1;
252: 		}
253: 		return 0;
254: 	});
255: 
256: 	return pluginArray;
257: };
