285: async function findNodeBBModules(dirs) {
286: 	const pluginPaths = [];
287: 	await Promise.all(dirs.map(async (dirname) => {
288: 		const dirPath = path.join(Plugins.nodeModulesPath, dirname);
289: 		const isDir = await isDirectory(dirPath);
290: 		if (!isDir) {
291: 			return;
292: 		}
293: 		if (pluginNamePattern.test(dirname)) {
294: 			pluginPaths.push(dirname);
295: 			return;
296: 		}
297: 
298: 		if (dirname[0] === '@') {
299: 			const subdirs = await fs.promises.readdir(dirPath);
300: 			await Promise.all(subdirs.map(async (subdir) => {
301: 				if (!pluginNamePattern.test(subdir)) {
302: 					return;
303: 				}
304: 
305: 				const subdirPath = path.join(dirPath, subdir);
306: 				const isDir = await isDirectory(subdirPath);
307: 				if (isDir) {
308: 					pluginPaths.push(`${dirname}/${subdir}`);
309: 				}
310: 			}));
311: 		}
312: 	}));
313: 	return pluginPaths;
314: }
