316: async function isDirectory(dirPath) {
317: 	try {
318: 		const stats = await fs.promises.stat(dirPath);
319: 		return stats.isDirectory();
320: 	} catch (err) {
321: 		if (err.code !== 'ENOENT') {
322: 			throw err;
323: 		}
324: 		return false;
325: 	}
326: }
