12: module.exports = function (Plugins) {
13: 	async function registerPluginAssets(pluginData, fields) {
14: 		function add(dest, arr) {
15: 			dest.push(...(arr || []));
16: 		}
17: 
18: 		const handlers = {
19: 			staticDirs: function (next) {
20: 				Plugins.data.getStaticDirectories(pluginData, next);
21: 			},
22: 			cssFiles: function (next) {
23: 				Plugins.data.getFiles(pluginData, 'css', next);
24: 			},
25: 			scssFiles: function (next) {
26: 				Plugins.data.getFiles(pluginData, 'scss', next);
27: 			},
28: 			acpScssFiles: function (next) {
29: 				Plugins.data.getFiles(pluginData, 'acpScss', next);
30: 			},
31: 			clientScripts: function (next) {
32: 				Plugins.data.getScripts(pluginData, 'client', next);
33: 			},
34: 			acpScripts: function (next) {
35: 				Plugins.data.getScripts(pluginData, 'acp', next);
36: 			},
37: 			modules: function (next) {
38: 				Plugins.data.getModules(pluginData, next);
39: 			},
40: 			languageData: function (next) {
41: 				Plugins.data.getLanguageData(pluginData, next);
42: 			},
43: 		};
44: 
45: 		let methods = {};
46: 		if (Array.isArray(fields)) {
47: 			fields.forEach((field) => {
48: 				methods[field] = handlers[field];
49: 			});
50: 		} else {
51: 			methods = handlers;
52: 		}
53: 
54: 		const results = await async.parallel(methods);
55: 
56: 		Object.assign(Plugins.staticDirs, results.staticDirs || {});
57: 		add(Plugins.cssFiles, results.cssFiles);
58: 		add(Plugins.scssFiles, results.scssFiles);
59: 		add(Plugins.acpScssFiles, results.acpScssFiles);
60: 		add(Plugins.clientScripts, results.clientScripts);
61: 		add(Plugins.acpScripts, results.acpScripts);
62: 		Object.assign(meta.js.scripts.modules, results.modules || {});
63: 		if (results.languageData) {
64: 			Plugins.languageData.languages = _.union(Plugins.languageData.languages, results.languageData.languages);
65: 			Plugins.languageData.namespaces = _.union(Plugins.languageData.namespaces, results.languageData.namespaces);
66: 			pluginData.languageData = results.languageData;
67: 		}
68: 		Plugins.pluginsData[pluginData.id] = pluginData;
69: 	}
