71: 	Plugins.prepareForBuild = async function (targets) {
72: 		const map = {
73: 			'plugin static dirs': ['staticDirs'],
74: 			'requirejs modules': ['modules'],
75: 			'client js bundle': ['clientScripts'],
76: 			'admin js bundle': ['acpScripts'],
77: 			'client side styles': ['cssFiles', 'scssFiles'],
78: 			'admin control panel styles': ['cssFiles', 'scssFiles', 'acpScssFiles'],
79: 			languages: ['languageData'],
80: 		};
81: 
82: 		const fields = _.uniq(_.flatMap(targets, target => map[target] || []));
83: 
84: 		// clear old data before build
85: 		fields.forEach((field) => {
86: 			switch (field) {
87: 				case 'clientScripts':
88: 				case 'acpScripts':
89: 				case 'cssFiles':
90: 				case 'scssFiles':
91: 				case 'acpScssFiles':
92: 					Plugins[field].length = 0;
93: 					break;
94: 				case 'languageData':
95: 					Plugins.languageData.languages = [];
96: 					Plugins.languageData.namespaces = [];
97: 					break;
98: 			// do nothing for modules and staticDirs
99: 			}
100: 		});
101: 
102: 		winston.verbose(`[plugins] loading the following fields from plugin data: ${fields.join(', ')}`);
103: 		const plugins = await Plugins.data.getActive();
104: 		await Promise.all(plugins.map(p => registerPluginAssets(p, fields)));
105: 	};
