107: 	Plugins.loadPlugin = async function (pluginPath) {
108: 		let pluginData;
109: 		try {
110: 			pluginData = await Plugins.data.loadPluginInfo(pluginPath);
111: 		} catch (err) {
112: 			if (err.message === '[[error:parse-error]]') {
113: 				return;
114: 			}
115: 			if (!themeNamePattern.test(pluginPath)) {
116: 				throw err;
117: 			}
118: 			return;
119: 		}
120: 		checkVersion(pluginData);
121: 
122: 		try {
123: 			registerHooks(pluginData);
124: 			await registerPluginAssets(pluginData);
125: 		} catch (err) {
126: 			winston.error(err.stack);
127: 			winston.verbose(`[plugins] Could not load plugin : ${pluginData.id}`);
128: 			return;
129: 		}
130: 
131: 		if (!pluginData.private) {
132: 			Plugins.loadedPlugins.push({
133: 				id: pluginData.id,
134: 				version: pluginData.version,
135: 			});
136: 		}
137: 
138: 		winston.verbose(`[plugins] Loaded plugin: ${pluginData.id}`);
139: 	};
140: 
141: 	function checkVersion(pluginData) {
142: 		function add() {
143: 			if (!Plugins.versionWarning.includes(pluginData.id)) {
144: 				Plugins.versionWarning.push(pluginData.id);
145: 			}
146: 		}
147: 
148: 		if (pluginData.nbbpm && pluginData.nbbpm.compatibility && semver.validRange(pluginData.nbbpm.compatibility)) {
149: 			if (!semver.satisfies(nconf.get('version'), pluginData.nbbpm.compatibility)) {
150: 				add();
151: 			}
152: 		} else {
153: 			add();
154: 		}
155: 	}
156: 
157: 	function registerHooks(pluginData) {
158: 		try {
159: 			if (!Plugins.libraries[pluginData.id]) {
160: 				Plugins.requireLibrary(pluginData);
161: 			}
162: 
163: 			if (Array.isArray(pluginData.hooks)) {
164: 				pluginData.hooks.forEach(hook => Plugins.hooks.register(pluginData.id, hook));
165: 			}
166: 		} catch (err) {
167: 			winston.warn(`[plugins] Unable to load library for: ${pluginData.id}`);
168: 			throw err;
169: 		}
170: 	}
171: };
