3: const fs = require('fs');
4: const path = require('path');
5: const winston = require('winston');
6: const _ = require('lodash');
7: const nconf = require('nconf');
8: 
9: const db = require('../database');
10: const file = require('../file');
11: const { paths } = require('../constants');
12: 
13: const Data = module.exports;
14: 
15: const basePath = path.join(__dirname, '../../');
16: 
17: // to get this functionality use `plugins.getActive()` from `src/plugins/install.js` instead
18: // this method duplicates that one, because requiring that file here would have side effects
19: async function getActiveIds() {
20: 	if (nconf.get('plugins:active')) {
21: 		return nconf.get('plugins:active');
22: 	}
23: 	return await db.getSortedSetRange('plugins:active', 0, -1);
24: }
