26: Data.getPluginPaths = async function () {
27: 	const plugins = await getActiveIds();
28: 	const pluginPaths = plugins.filter(plugin => plugin && typeof plugin === 'string')
29: 		.map(plugin => path.join(paths.nodeModules, plugin));
30: 	const exists = await Promise.all(pluginPaths.map(file.exists));
31: 	exists.forEach((exists, i) => {
32: 		if (!exists) {
33: 			winston.warn(`[plugins] "${plugins[i]}" is active but not installed.`);
34: 		}
35: 	});
36: 	return pluginPaths.filter((p, i) => exists[i]);
37: };
