39: Data.loadPluginInfo = async function (pluginPath) {
40: 	const [packageJson, pluginJson] = await Promise.all([
41: 		fs.promises.readFile(path.join(pluginPath, 'package.json'), 'utf8'),
42: 		fs.promises.readFile(path.join(pluginPath, 'plugin.json'), 'utf8'),
43: 	]);
44: 
45: 	let pluginData;
46: 	let packageData;
47: 	try {
48: 		pluginData = JSON.parse(pluginJson);
49: 		packageData = JSON.parse(packageJson);
50: 
51: 		pluginData.license = parseLicense(packageData);
52: 
53: 		pluginData.id = packageData.name;
54: 		pluginData.name = packageData.name;
55: 		pluginData.description = packageData.description;
56: 		pluginData.version = packageData.version;
57: 		pluginData.repository = packageData.repository;
58: 		pluginData.nbbpm = packageData.nbbpm;
59: 		pluginData.path = pluginPath;
60: 	} catch (err) {
61: 		const pluginDir = path.basename(pluginPath);
62: 
63: 		winston.error(`[plugins/${pluginDir}] Error in plugin.json or package.json!${err.stack}`);
64: 		throw new Error('[[error:parse-error]]');
65: 	}
66: 	return pluginData;
67: };
68: 
69: function parseLicense(packageData) {
70: 	try {
71: 		const licenseData = require(`spdx-license-list/licenses/${packageData.license}`);
72: 		return {
73: 			name: licenseData.name,
74: 			text: licenseData.licenseText,
75: 		};
76: 	} catch (e) {
77: 		// No license matched
78: 		return null;
79: 	}
80: }
