88: Data.getStaticDirectories = async function (pluginData) {
89: 	const validMappedPath = /^[\w\-_]+$/;
90: 
91: 	if (!pluginData.staticDirs) {
92: 		return;
93: 	}
94: 
95: 	const dirs = Object.keys(pluginData.staticDirs);
96: 	if (!dirs.length) {
97: 		return;
98: 	}
99: 
100: 	const staticDirs = {};
101: 
102: 	async function processDir(route) {
103: 		if (!validMappedPath.test(route)) {
104: 			winston.warn(`[plugins/${pluginData.id}] Invalid mapped path specified: ${
105: 				route}. Path must adhere to: ${validMappedPath.toString()}`);
106: 			return;
107: 		}
108: 		const dirPath = await resolveModulePath(pluginData.path, pluginData.staticDirs[route]);
109: 		if (!dirPath) {
110: 			winston.warn(`[plugins/${pluginData.id}] Invalid mapped path specified: ${
111: 				route} => ${pluginData.staticDirs[route]}`);
112: 			return;
113: 		}
114: 		try {
115: 			const stats = await fs.promises.stat(dirPath);
116: 			if (!stats.isDirectory()) {
117: 				winston.warn(`[plugins/${pluginData.id}] Mapped path '${
118: 					route} => ${dirPath}' is not a directory.`);
119: 				return;
120: 			}
121: 
122: 			staticDirs[`${pluginData.id}/${route}`] = dirPath;
123: 		} catch (err) {
124: 			if (err.code === 'ENOENT') {
125: 				winston.warn(`[plugins/${pluginData.id}] Mapped path '${
126: 					route} => ${dirPath}' not found.`);
127: 				return;
128: 			}
129: 			throw err;
130: 		}
131: 	}
132: 
133: 	await Promise.all(dirs.map(route => processDir(route)));
134: 	winston.verbose(`[plugins] found ${Object.keys(staticDirs).length} static directories for ${pluginData.id}`);
135: 	return staticDirs;
136: };
