138: 
139: Data.getFiles = async function (pluginData, type) {
140: 	if (!Array.isArray(pluginData[type]) || !pluginData[type].length) {
141: 		return;
142: 	}
143: 
144: 	winston.verbose(`[plugins] Found ${pluginData[type].length} ${type} file(s) for plugin ${pluginData.id}`);
145: 
146: 	return pluginData[type].map(file => path.join(pluginData.id, file));
147: };
