149: /**
150:  * With npm@3, dependencies can become flattened, and appear at the root level.
151:  * This method resolves these differences if it can.
152:  */
153: async function resolveModulePath(basePath, modulePath) {
154: 	const isNodeModule = /node_modules/;
155: 
156: 	const currentPath = path.join(basePath, modulePath);
157: 	const exists = await file.exists(currentPath);
158: 	if (exists) {
159: 		return currentPath;
160: 	}
161: 	if (!isNodeModule.test(modulePath)) {
162: 		winston.warn(`[plugins] File not found: ${currentPath} (Ignoring)`);
163: 		return;
164: 	}
165: 
166: 	const dirPath = path.dirname(basePath);
167: 	if (dirPath === basePath) {
168: 		winston.warn(`[plugins] File not found: ${currentPath} (Ignoring)`);
169: 		return;
170: 	}
171: 
172: 	return await resolveModulePath(dirPath, modulePath);
173: }
174: 
175: 
176: Data.getScripts = async function getScripts(pluginData, target) {
177: 	target = (target === 'client') ? 'scripts' : 'acpScripts';
178: 
179: 	const input = pluginData[target];
180: 	if (!Array.isArray(input) || !input.length) {
181: 		return;
182: 	}
183: 
184: 	const scripts = [];
185: 
186: 	for (const filePath of input) {
187: 		/* eslint-disable no-await-in-loop */
188: 		const modulePath = await resolveModulePath(pluginData.path, filePath);
189: 		if (modulePath) {
190: 			scripts.push(modulePath);
191: 		}
192: 	}
193: 	if (scripts.length) {
194: 		winston.verbose(`[plugins] Found ${scripts.length} js file(s) for plugin ${pluginData.id}`);
195: 	}
196: 	return scripts;
197: };
198: 
