200: Data.getModules = async function getModules(pluginData) {
201: 	if (!pluginData.modules || !pluginData.hasOwnProperty('modules')) {
202: 		return;
203: 	}
204: 
205: 	let pluginModules = pluginData.modules;
206: 
207: 	if (Array.isArray(pluginModules)) {
208: 		const strip = parseInt(pluginData.modulesStrip, 10) || 0;
209: 
210: 		pluginModules = pluginModules.reduce((prev, modulePath) => {
211: 			let key;
212: 			if (strip) {
213: 				key = modulePath.replace(new RegExp(`.?(/[^/]+){${strip}}/`), '');
214: 			} else {
215: 				key = path.basename(modulePath);
216: 			}
217: 
218: 			prev[key] = modulePath;
219: 			return prev;
220: 		}, {});
221: 	}
222: 
223: 	const modules = {};
224: 	async function processModule(key) {
225: 		const modulePath = await resolveModulePath(pluginData.path, pluginModules[key]);
226: 		if (modulePath) {
227: 			modules[key] = path.relative(basePath, modulePath);
228: 		}
229: 	}
230: 
231: 	await Promise.all(Object.keys(pluginModules).map(key => processModule(key)));
232: 
233: 	const len = Object.keys(modules).length;
234: 	winston.verbose(`[plugins] Found ${len} AMD-style module(s) for plugin ${pluginData.id}`);
235: 	return modules;
236: };
237: 
238: Data.getLanguageData = async function getLanguageData(pluginData) {
239: 	if (typeof pluginData.languages !== 'string') {
240: 		return;
241: 	}
242: 
243: 	const pathToFolder = path.join(paths.nodeModules, pluginData.id, pluginData.languages);
244: 	const filepaths = await file.walk(pathToFolder);
245: 
246: 	const namespaces = [];
247: 	const languages = [];
248: 
249: 	filepaths.forEach((p) => {
250: 		const rel = path.relative(pathToFolder, p).split(/[/\\]/);
251: 		const language = rel.shift().replace('_', '-').replace('@', '-x-');
252: 		const namespace = rel.join('/').replace(/\.json$/, '');
253: 
254: 		if (!language || !namespace) {
255: 			return;
256: 		}
257: 
258: 		languages.push(language);
259: 		namespaces.push(namespace);
260: 	});
261: 	return {
262: 		languages: _.uniq(languages),
263: 		namespaces: _.uniq(namespaces),
264: 	};
265: };
