const pluginNamePattern = /^(@[\w-]+\/)?nodebb-(theme|plugin|widget|rewards)-[\w-]+$/;

describe('Plugin ID Validation', () => {
	describe('Valid plugin IDs', () => {
		const validIds = [
			'nodebb-plugin-markdown',
			'nodebb-plugin-dbsearch',
			'nodebb-plugin-location-to-map',
			'nodebb-theme-persona',
			'nodebb-widget-example',
			'nodebb-rewards-points',
			'@myorg/nodebb-plugin-custom',
			'@scope/nodebb-theme-dark',
		];

		validIds.forEach(id => {
			it(`should accept valid ID: ${id}`, () => {
				assert(pluginNamePattern.test(id), `ID ${id} should be valid`);
			});
		});
	});

	describe('Invalid plugin IDs', () => {
		const invalidIds = [
			'notaplugin',
			'not-a-plugin',
			'\t\nnodebb-plugin',
			'nodebb-plugin',
			'  nodebb-plugin-test',
			'nodebb-plugin-test  ',
			'invalid plugin id',
			'nodebb-invalid-type-test',
			'nodebb-plugin-',
			'',
			'plugin-with-whitespace in name',
		];

		invalidIds.forEach(id => {
			it(`should reject invalid ID: "${id}"`, () => {
				assert(!pluginNamePattern.test(id), `ID "${id}" should be invalid`);
			});
		});
	});
});

// Test for CLI activation validation
describe('CLI Activation Validation', () => {
	it('should validate plugin ID after auto-complete', () => {
		// This tests that the validation check we added in the activate function
		// on line 66-68 of manage.js will catch invalid IDs
		const invalidId = 'not-a-valid-plugin';
		assert(!pluginNamePattern.test(invalidId), 'Should reject invalid plugin ID');
	});

	it('should accept valid plugin IDs after auto-complete', () => {
		const validId = 'nodebb-plugin-markdown';
		assert(pluginNamePattern.test(validId), 'Should accept valid plugin ID');
	});
});

