// Comprehensive test of the plugin name pattern validation
'use strict';

const pluginNamePattern = /^(@[\w-]+\/)?nodebb-(theme|plugin|widget|rewards)-[\w-]+$/;

console.log('Plugin Name Pattern Validation Tests\n');
console.log('Pattern:', pluginNamePattern);
console.log('\n');

// Test cases
const testCases = [
    // Valid IDs
    { id: 'nodebb-plugin-markdown', valid: true, description: 'Basic plugin' },
    { id: 'nodebb-plugin-dbsearch', valid: true, description: 'Plugin with hyphenated name' },
    { id: 'nodebb-plugin-imgur', valid: true, description: 'Plugin with alphanumeric name' },
    { id: 'nodebb-theme-persona', valid: true, description: 'Theme' },
    { id: 'nodebb-theme-harmony', valid: true, description: 'Another theme' },
    { id: 'nodebb-widget-example', valid: true, description: 'Widget' },
    { id: 'nodebb-rewards-points', valid: true, description: 'Rewards plugin' },
    { id: '@myorg/nodebb-plugin-custom', valid: true, description: 'Scoped plugin' },
    { id: '@scope/nodebb-theme-dark', valid: true, description: 'Scoped theme' },
    { id: '@org-with-hyphen/nodebb-plugin-test', valid: true, description: 'Scoped with hyphens' },
    { id: 'nodebb-plugin-a', valid: true, description: 'Minimal plugin name' },
    { id: 'nodebb-plugin-test123', valid: true, description: 'Plugin with numbers' },

    // Invalid IDs - No prefix
    { id: 'notaplugin', valid: false, description: 'Missing nodebb- prefix' },
    { id: 'not-a-plugin', valid: false, description: 'Wrong prefix format' },
    { id: 'markdown', valid: false, description: 'Just the name' },

    // Invalid IDs - Whitespace
    { id: '\t\nnodebb-plugin', valid: false, description: 'Leading whitespace (tab and newline)' },
    { id: '  nodebb-plugin-test', valid: false, description: 'Leading spaces' },
    { id: 'nodebb-plugin-test  ', valid: false, description: 'Trailing spaces' },
    { id: 'nodebb-plugin test', valid: false, description: 'Space in middle' },
    { id: 'nodebb-plugin\ntest', valid: false, description: 'Newline in middle' },
    { id: 'nodebb-plugin\ttest', valid: false, description: 'Tab in middle' },

    // Invalid IDs - Wrong type
    { id: 'nodebb-invalid-type-test', valid: false, description: 'Invalid plugin type' },
    { id: 'nodebb-foo-bar', valid: false, description: 'Non-existent type' },

    // Invalid IDs - Incomplete
    { id: 'nodebb-plugin', valid: false, description: 'Missing plugin name' },
    { id: 'nodebb-plugin-', valid: false, description: 'Empty plugin name' },
    { id: 'nodebb-', valid: false, description: 'Missing type and name' },
    { id: 'nodebb', valid: false, description: 'Just nodebb' },

    // Invalid IDs - Special characters
    { id: 'nodebb-plugin-test@name', valid: false, description: 'Contains @ in the middle' },
    { id: 'nodebb-plugin-test!', valid: false, description: 'Contains exclamation' },
    { id: 'nodebb-plugin-test$', valid: false, description: 'Contains dollar sign' },
    { id: 'nodebb-plugin-test*', valid: false, description: 'Contains asterisk' },

    // Invalid IDs - Empty or malformed
    { id: '', valid: false, description: 'Empty string' },
    { id: '@', valid: false, description: 'Just @' },
    { id: '@/', valid: false, description: 'Invalid scope' },
    { id: '@scope/', valid: false, description: 'Missing package name after scope' },
];

let passCount = 0;
let failCount = 0;

